#include <iostream>
using namespace std;
bool areAnagrams(string &s1, string &s2) {
if (s1.length() != s2.length())
return false;
// Sort both strings
sort(s1.begin(), s1.end());
sort(s2.begin(), s2.end());
// Compare sorted strings
return (s1 == s2);
}
